package com.urbanvogue.apigateway.filter;

import com.urbanvogue.apigateway.util.JwtUtil;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.cloud.gateway.filter.GatewayFilter;
import org.springframework.cloud.gateway.filter.factory.AbstractGatewayFilterFactory;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Component;

@Component
public class AuthenticationFilter extends AbstractGatewayFilterFactory<AuthenticationFilter.Config> {

    @Autowired
    private JwtUtil jwtUtil;

    public AuthenticationFilter() {
        super(Config.class);
    }

    @Override
    public GatewayFilter apply(Config config) {
        return ((exchange, chain) -> {

            // Allow public paths
            String path = exchange.getRequest().getURI().getPath();
            if (path.startsWith("/api/auth/register") || path.startsWith("/api/auth/login") || path.equals("/api/products")) {
                return chain.filter(exchange);
            }

            if (!exchange.getRequest().getHeaders().containsKey(HttpHeaders.AUTHORIZATION)) {
                exchange.getResponse().setStatusCode(HttpStatus.UNAUTHORIZED);
                return exchange.getResponse().setComplete();
            }

            String authHeader = exchange.getRequest().getHeaders().get(HttpHeaders.AUTHORIZATION).get(0);
            if (authHeader != null && authHeader.startsWith("Bearer ")) {
                authHeader = authHeader.substring(7);
            }

            try {
                jwtUtil.validateToken(authHeader);
                String username = jwtUtil.extractUsername(authHeader);

                // Mutate the request to add the username header
                exchange.getRequest().mutate()
                        .header("X-Logged-In-User", username)
                        .build();

            } catch (Exception e) {
                System.out.println("Invalid token: " + e.getMessage());
                exchange.getResponse().setStatusCode(HttpStatus.UNAUTHORIZED);
                return exchange.getResponse().setComplete();
            }

            return chain.filter(exchange);
        });
    }

    public static class Config { }
}

package com.urbanvogue.apigateway.filter;

import com.urbanvogue.apigateway.util.JwtUtil;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.cloud.gateway.filter.GatewayFilter;
import org.springframework.cloud.gateway.filter.factory.AbstractGatewayFilterFactory;
import org.springframework.http.HttpHeaders;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Component;

@Component
public class AuthenticationFilter extends AbstractGatewayFilterFactory<AuthenticationFilter.Config> {

    @Autowired
    private JwtUtil jwtUtil;

    public AuthenticationFilter() {
        super(Config.class);
    }

    @Override
    public GatewayFilter apply(Config config) {
        return ((exchange, chain) -> {

            // Allow public paths
            String path = exchange.getRequest().getURI().getPath();
            if (path.startsWith("/api/auth/register") || path.startsWith("/api/auth/login") || path.equals("/api/products") || path.startsWith("/api/users/exists/")) {
                return chain.filter(exchange);
            }

            if (!exchange.getRequest().getHeaders().containsKey(HttpHeaders.AUTHORIZATION)) {
                exchange.getResponse().setStatusCode(HttpStatus.UNAUTHORIZED);
                return exchange.getResponse().setComplete();
            }

            String authHeader = exchange.getRequest().getHeaders().get(HttpHeaders.AUTHORIZATION).get(0);
            if (authHeader != null && authHeader.startsWith("Bearer ")) {
                authHeader = authHeader.substring(7);
            }

            try {
                jwtUtil.validateToken(authHeader);
                String username = jwtUtil.extractUsername(authHeader);

                // Mutate the request to add the username header
                exchange.getRequest().mutate()
                        .header("X-Logged-In-User", username)
                        .build();

            } catch (Exception e) {
                System.out.println("Invalid token: " + e.getMessage());
                exchange.getResponse().setStatusCode(HttpStatus.UNAUTHORIZED);
                return exchange.getResponse().setComplete();
            }

            return chain.filter(exchange);
        });
    }

    public static class Config { }
}

package com.urbanvogue.auth.controller;

import com.urbanvogue.auth.model.User;
import com.urbanvogue.auth.repository.UserRepository;
import com.urbanvogue.auth.service.AuthService;
import com.urbanvogue.auth.util.JwtUtils;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestTemplate;
import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    @Autowired
    private AuthService authService;

    @Autowired
    private JwtUtils jwtUtils;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private RestTemplate restTemplate;

    @Value("${notification.service.url}")
    private String notificationServiceUrl;

    private final BCryptPasswordEncoder passwordEncoder =
            new BCryptPasswordEncoder();

    // ── REGISTER ──
    @PostMapping("/register")
    public String register(@RequestBody User user) {
        authService.register(user);

        // ── Notify: Send welcome email ──
        try {
            String notifyUrl = notificationServiceUrl +
                    "/api/notifications/welcome?username=" +
                    user.getUsername();
            restTemplate.postForObject(notifyUrl, null, Object.class);
            System.out.println(
                    "✅ Welcome notification sent for: " +
                            user.getUsername()
            );
        } catch (Exception e) {
            System.err.println(
                    "⚠️ Could not send welcome notification: " +
                            e.getMessage()
            );
        }

        return "User registered successfully!";
    }

    // ── LOGIN — Returns token + user info ──
    @PostMapping("/login")
    public Map<String, String> login(@RequestBody User loginRequest) {

        User user = userRepository
                .findByUsername(loginRequest.getUsername())
                .orElseThrow(() ->
                        new RuntimeException("User not found")
                );

        if (!passwordEncoder.matches(
                loginRequest.getPassword(), user.getPassword())) {
            throw new RuntimeException("Invalid Credentials");
        }

        // Generate token with username AND role
        String token = jwtUtils.generateToken(
                user.getUsername(),
                user.getRole()
        );

        // ── Notify: Send login notification ──
        try {
            String notifyUrl = notificationServiceUrl +
                    "/api/notifications/send";

            Map<String, Object> notificationBody = new HashMap<>();
            notificationBody.put("recipientUsername",
                    user.getUsername());
            notificationBody.put("type", "LOGIN");
            notificationBody.put("channel", "EMAIL");
            notificationBody.put("message",
                    "Hello " + user.getUsername() +
                            "! You have successfully logged in to " +
                            "UrbanVogue. If this wasn't you, " +
                            "please change your password immediately."
            );

            restTemplate.postForObject(
                    notifyUrl, notificationBody, Object.class
            );
            System.out.println(
                    "✅ Login notification sent for: " +
                            user.getUsername()
            );
        } catch (Exception e) {
            System.err.println(
                    "⚠️ Could not send login notification: " +
                            e.getMessage()
            );
        }

        // Return token with helpful info
        Map<String, String> response = new HashMap<>();
        response.put("token", token);
        response.put("username", user.getUsername());
        response.put("role", user.getRole());
        response.put("expiresIn", "72 hours");
        response.put("message", "Login successful!");

        return response;
    }

    // ── VALIDATE — Check if token is still valid ──
    @PostMapping("/validate")
    public Map<String, Object> validateToken(
            @RequestHeader("Authorization") String authHeader) {

        Map<String, Object> response = new HashMap<>();

        if (authHeader == null || !authHeader.startsWith("Bearer ")) {
            response.put("valid", false);
            response.put("message", "No token provided");
            return response;
        }

        String token = authHeader.substring(7); // Remove "Bearer "

        if (jwtUtils.validateToken(token)) {
            response.put("valid", true);
            response.put("username",
                    jwtUtils.getUsernameFromToken(token));
            response.put("role",
                    jwtUtils.getRoleFromToken(token));
            response.put("expired", false);
            response.put("message", "Token is valid");
        } else {
            response.put("valid", false);
            response.put("expired", true);
            response.put("message",
                    "Token is expired or invalid. Please login again.");
        }

        return response;
    }

    // ── DELETE USER CREDENTIALS (Called by user-service) ──
    @DeleteMapping("/{username}")
    public String deleteUser(@PathVariable String username) {
        authService.deleteUser(username);
        return "Auth credentials deleted for " + username;
    }
}

package com.urbanvogue.auth.controller;

import com.urbanvogue.auth.dto.RegistrationRequest;
import com.urbanvogue.auth.model.User;
import com.urbanvogue.auth.repository.UserRepository;
import com.urbanvogue.auth.service.AuthService;
import com.urbanvogue.auth.util.JwtUtils;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.client.RestTemplate;
import java.util.HashMap;
import java.util.Map;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    @Autowired
    private AuthService authService;

    @Autowired
    private JwtUtils jwtUtils;

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private RestTemplate restTemplate;

    @Value("${notification.service.url}")
    private String notificationServiceUrl;

    @Value("${user.service.url}")
    private String userServiceUrl;

    private final BCryptPasswordEncoder passwordEncoder =
            new BCryptPasswordEncoder();

    // ── REGISTER (Amazon-style: One form creates both auth + profile) ──
    @PostMapping("/register")
    public Map<String, Object> register(@RequestBody RegistrationRequest request) {
        Map<String, Object> response = new HashMap<>();

        try {
            // 1. Create auth credentials in users table
            User user = new User();
            user.setUsername(request.getUsername());
            user.setPassword(passwordEncoder.encode(request.getPassword()));
            user.setRole(request.getRole() != null ? request.getRole() : "ROLE_USER");

            User savedUser = authService.register(user);

            // 2. Auto-create user profile in user-service
            Map<String, Object> profileData = new HashMap<>();
            profileData.put("username", request.getUsername());
            profileData.put("fullName", request.getFullName());
            profileData.put("age", request.getAge());
            profileData.put("sex", request.getSex());
            profileData.put("address", request.getAddress());
            profileData.put("email", request.getEmail());

            try {
                String profileUrl = userServiceUrl + "/api/users";
                restTemplate.postForObject(profileUrl, profileData, Object.class);
                System.out.println("✅ User profile created for: " + request.getUsername());
            } catch (Exception e) {
                System.err.println("⚠️ Could not create user profile: " + e.getMessage());
                // Don't fail registration if profile creation fails
            }

            // ── Notify: Send welcome email ──
            try {
                String notifyUrl = notificationServiceUrl +
                        "/api/notifications/welcome?username=" +
                        request.getUsername();
                restTemplate.postForObject(notifyUrl, null, Object.class);
                System.out.println("✅ Welcome notification sent for: " + request.getUsername());
            } catch (Exception e) {
                System.err.println("⚠️ Could not send welcome notification: " + e.getMessage());
            }

            response.put("success", true);
            response.put("message", "Registration successful! Welcome to Urban Vogue.");
            response.put("username", request.getUsername());

        } catch (Exception e) {
            response.put("success", false);
            response.put("message", "Registration failed: " + e.getMessage());
        }

        return response;
    }

    // ── LOGIN — Returns token + user info ──
    @PostMapping("/login")
    public Map<String, Object> login(@RequestBody User loginRequest) {
        Map<String, Object> response = new HashMap<>();

        try {
            User user = userRepository
                    .findByUsername(loginRequest.getUsername())
                    .orElseThrow(() ->
                            new RuntimeException("User not found")
                    );

            if (!passwordEncoder.matches(
                    loginRequest.getPassword(), user.getPassword())) {
                throw new RuntimeException("Invalid Credentials");
            }

            // ── Generate token with username AND role ──
            String token = jwtUtils.generateToken(
                    user.getUsername(),
                    user.getRole()
            );

            // ── Notify: Send login notification ──
            try {
                String notifyUrl = notificationServiceUrl +
                        "/api/notifications/send";

                Map<String, Object> notificationBody = new HashMap<>();
                notificationBody.put("recipientUsername",
                        user.getUsername());
                notificationBody.put("type", "LOGIN");
                notificationBody.put("channel", "EMAIL");
                notificationBody.put("message",
                        "Hello " + user.getUsername() +
                                "! You have successfully logged in to " +
                                "UrbanVogue. If this wasn't you, " +
                                "please change your password immediately."
                );

                restTemplate.postForObject(
                        notifyUrl, notificationBody, Object.class
                );
                System.out.println(
                        "✅ Login notification sent for: " +
                                user.getUsername()
                );
            } catch (Exception e) {
                System.err.println(
                        "⚠️ Could not send login notification: " +
                        e.getMessage()
                );
            }

            response.put("success", true);
            response.put("token", token);
            response.put("username", user.getUsername());
            response.put("role", user.getRole());
            response.put("userId", user.getId());
            response.put("expiresIn", "72 hours");
            response.put("message", "Login successful!");

        } catch (Exception e) {
            response.put("success", false);
            response.put("message", e.getMessage());
        }

        return response;
    }

    // ── VALIDATE — Check if token is still valid ──
    @PostMapping("/validate")
    public Map<String, Object> validateToken(
            @RequestHeader("Authorization") String authHeader) {

        Map<String, Object> response = new HashMap<>();

        if (authHeader == null || !authHeader.startsWith("Bearer ")) {
            response.put("valid", false);
            response.put("message", "No token provided");
            return response;
        }

        String token = authHeader.substring(7); // Remove "Bearer "

        if (jwtUtils.validateToken(token)) {
            response.put("valid", true);
            response.put("username",
                    jwtUtils.getUsernameFromToken(token));
            response.put("role",
                    jwtUtils.getRoleFromToken(token));
            response.put("expired", false);
            response.put("message", "Token is valid");
        } else {
            response.put("valid", false);
            response.put("expired", true);
            response.put("message",
                    "Token is expired or invalid. Please login again.");
        }

        return response;
    }

    // ── DELETE USER CREDENTIALS (Called by user-service) ──
    @DeleteMapping("/{username}")
    public String deleteUser(@PathVariable String username) {
        authService.deleteUser(username);
        return "Auth credentials deleted for " + username;
    }
}

package com.urbanvogue.auth.dto;

import lombok.AllArgsConstructor;
import lombok.Data;
import lombok.NoArgsConstructor;

@Data
@NoArgsConstructor
@AllArgsConstructor
public class RegistrationRequest {
    // Auth fields
    private String username;
    private String password;
    private String role; // Default to "ROLE_USER" if not provided

    // Profile fields
    private String fullName;
    private Integer age;
    private String sex;
    private String address;
    private String email;
}

package com.urbanvogue.user.controller;

import com.urbanvogue.user.dto.UserProfileDashboard;
import com.urbanvogue.user.model.UserProfile;
import com.urbanvogue.user.service.UserService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/users")
public class UserController {

    @Autowired
    private UserService userService;

    // Create or Update Profile
    @PostMapping
    public UserProfile saveProfile(@RequestBody UserProfile profile) {
        return userService.createOrUpdateProfile(profile);
    }

    // Get Basic Profile Details
    @GetMapping("/{username}")
    public UserProfile getProfile(@PathVariable String username) {
        return userService.getProfile(username);
    }

    // Get Profile Dashboard (Includes Order History)
    @GetMapping("/{username}/dashboard")
    public UserProfileDashboard getDashboard(@PathVariable String username) {
        return userService.getDashboard(username);
    }

    // Delete Account (Cascades to Auth Service)
    @DeleteMapping("/{username}")
    public String deleteAccount(@PathVariable String username) {
        userService.deleteAccount(username);
        return "Account successfully deleted for user: " + username;
    }
}

package com.urbanvogue.user.controller;

import com.urbanvogue.user.dto.UserProfileDashboard;
import com.urbanvogue.user.model.UserProfile;
import com.urbanvogue.user.service.UserService;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/users")
public class UserController {

    @Autowired
    private UserService userService;

    // Create or Update Profile
    @PostMapping
    public UserProfile saveProfile(@RequestBody UserProfile profile) {
        return userService.createOrUpdateProfile(profile);
    }

    // ── NEW: Amazon-style "My Account" endpoint (scoped to logged-in user) ──
    @GetMapping("/me")
    public UserProfile getMyProfile(@RequestHeader("X-Logged-In-User") String username) {
        return userService.getProfile(username);
    }

    // ── NEW: Amazon-style "My Dashboard" endpoint (scoped to logged-in user) ──
    @GetMapping("/me/dashboard")
    public UserProfileDashboard getMyDashboard(@RequestHeader("X-Logged-In-User") String username) {
        return userService.getDashboard(username);
    }

    // ── NEW: Check if profile exists (for auth-service login verification) ──
    @GetMapping("/exists/{username}")
    public boolean profileExists(@PathVariable String username) {
        return userService.profileExists(username);
    }

    // Get Basic Profile Details (for internal service-to-service calls)
    @GetMapping("/{username}")
    public UserProfile getProfile(@PathVariable String username) {
        return userService.getProfile(username);
    }

    // Get Profile Dashboard (Includes Order History) (for internal service-to-service calls)
    @GetMapping("/{username}/dashboard")
    public UserProfileDashboard getDashboard(@PathVariable String username) {
        return userService.getDashboard(username);
    }

    // Delete Account (Cascades to Auth Service)
    @DeleteMapping("/{username}")
    public String deleteAccount(@PathVariable String username) {
        userService.deleteAccount(username);
        return "Account successfully deleted for user: " + username;
    }
}

package com.urbanvogue.user.service;

import com.urbanvogue.user.dto.UserProfileDashboard;
import com.urbanvogue.user.model.UserProfile;
import com.urbanvogue.user.repository.UserRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestTemplate;

import java.util.Arrays;
import java.util.List;

@Service
public class UserService {

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private RestTemplate restTemplate;

    @Value("${order.service.url}")
    private String orderServiceUrl;

    @Value("${auth.service.url}")
    private String authServiceUrl;

    public UserProfile createOrUpdateProfile(UserProfile profile) {
        UserProfile existing = userRepository.findByUsername(profile.getUsername()).orElse(null);
        if (existing != null) {
            existing.setFullName(profile.getFullName());
            existing.setAge(profile.getAge());
            existing.setSex(profile.getSex());
            existing.setAddress(profile.getAddress());
            existing.setEmail(profile.getEmail());
            return userRepository.save(existing);
        }
        return userRepository.save(profile);
    }

    public UserProfile getProfile(String username) {
        return userRepository.findByUsername(username)
                .orElseThrow(() -> new RuntimeException("User profile not found for: " + username));
    }

    public UserProfileDashboard getDashboard(String username) {
        UserProfile profile = getProfile(username);

        // Fetch Order History from order-service
        List<Object> orders;
        try {
            String url = orderServiceUrl + "/api/orders/customer/" + username;
            Object[] orderArray = restTemplate.getForObject(url, Object[].class);
            orders = orderArray != null ? Arrays.asList(orderArray) : List.of();
        } catch (Exception e) {
            System.err.println("Could not fetch orders for " + username + ": " + e.getMessage());
            orders = List.of(); // Return empty list if order-service is down
        }

        UserProfileDashboard dashboard = new UserProfileDashboard();
        dashboard.setProfile(profile);
        dashboard.setOrderHistory(orders);
        return dashboard;
    }

    public void deleteAccount(String username) {
        UserProfile profile = getProfile(username);

        // 1. Delete profile from user-service DB
        userRepository.delete(profile);

        // 2. Instruct auth-service to delete login credentials
        try {
            String url = authServiceUrl + "/api/auth/" + username;
            restTemplate.delete(url);
            System.out.println("✅ Successfully deleted auth credentials for: " + username);
        } catch (Exception e) {
            System.err.println("⚠️ Could not delete auth credentials for " + username + ": " + e.getMessage());
        }
    }
}

package com.urbanvogue.user.service;

import com.urbanvogue.user.dto.UserProfileDashboard;
import com.urbanvogue.user.model.UserProfile;
import com.urbanvogue.user.repository.UserRepository;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestTemplate;

import java.util.Arrays;
import java.util.List;

@Service
public class UserService {

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private RestTemplate restTemplate;

    @Value("${order.service.url}")
    private String orderServiceUrl;

    @Value("${auth.service.url}")
    private String authServiceUrl;

    public UserProfile createOrUpdateProfile(UserProfile profile) {
        UserProfile existing = userRepository.findByUsername(profile.getUsername()).orElse(null);
        if (existing != null) {
            existing.setFullName(profile.getFullName());
            existing.setAge(profile.getAge());
            existing.setSex(profile.getSex());
            existing.setAddress(profile.getAddress());
            existing.setEmail(profile.getEmail());
            return userRepository.save(existing);
        }
        return userRepository.save(profile);
    }

    public UserProfile getProfile(String username) {
        return userRepository.findByUsername(username)
                .orElseThrow(() -> new RuntimeException("User profile not found for: " + username));
    }

    public UserProfileDashboard getDashboard(String username) {
        UserProfile profile = getProfile(username);

        // Fetch Order History from order-service
        List<Object> orders;
        try {
            String url = orderServiceUrl + "/api/orders/customer/" + username;
            Object[] orderArray = restTemplate.getForObject(url, Object[].class);
            orders = orderArray != null ? Arrays.asList(orderArray) : List.of();
        } catch (Exception e) {
            System.err.println("Could not fetch orders for " + username + ": " + e.getMessage());
            orders = List.of(); // Return empty list if order-service is down
        }

        UserProfileDashboard dashboard = new UserProfileDashboard();
        dashboard.setProfile(profile);
        dashboard.setOrderHistory(orders);
        return dashboard;
    }

    public void deleteAccount(String username) {
        UserProfile profile = getProfile(username);

        // 1. Delete profile from user-service DB
        userRepository.delete(profile);

        // 2. Instruct auth-service to delete login credentials
        try {
            String url = authServiceUrl + "/api/auth/" + username;
            restTemplate.delete(url);
            System.out.println("✅ Successfully deleted auth credentials for: " + username);
        } catch (Exception e) {
            System.err.println("⚠️ Could not delete auth credentials for " + username + ": " + e.getMessage());
        }
    }

    // ── NEW: Check if profile exists (for auth-service login verification) ──
    public boolean profileExists(String username) {
        try {
            return userRepository.findByUsername(username).isPresent();
        } catch (Exception e) {
            return false;
        }
    }
}
